const http=require("http"),fs=require("fs"),path=require("path");
const ROOT=process.env.NV_ROOT;
const MIME={".html":"text/html; charset=utf-8",".css":"text/css; charset=utf-8",".js":"application/javascript; charset=utf-8",".svg":"image/svg+xml",".png":"image/png",".gif":"image/gif",".jpg":"image/jpeg",".ico":"image/x-icon"};
http.createServer((req,res)=>{
  let p=decodeURIComponent(req.url.split("?")[0]);
  if(p.endsWith("/"))p+="index.html";
  let fp=path.join(ROOT,p);
  fs.readFile(fp,(e,d)=>{
    if(e){res.writeHead(404);res.end("404");return;}
    res.writeHead(200,{"Content-Type":MIME[path.extname(fp).toLowerCase()]||"application/octet-stream"});
    res.end(d);
  });
}).listen(4521,"127.0.0.1",()=>console.log("serving",ROOT,"on 4521"));
